1	export interface QuoteItem {
2	  type: string;
3	}
4	
5	export interface QuoteInput {
6	  items: QuoteItem[];
7	  customer: { yearsWithMHPCO: number };
8	  isFollowUp: boolean;
9	}
10	
11	const PROCESSING_FEE = 5;
12	const FIRST_INSURANCE_RATE = 0.1;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	};
21	
22	export function quote(input: QuoteInput): number {
23	  let policyBase = 0;
24	  for (const item of input.items) {
25	    policyBase += BASE_PREMIUM[item.type];
26	  }
27	  const policyPremium = policyBase + policyBase * FIRST_INSURANCE_RATE;
28	  return Math.ceil(policyPremium + PROCESSING_FEE);
29	}
30	
